import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import Header from './Header';
import 'bootstrap/dist/css/bootstrap.min.css';
import '@fortawesome/fontawesome-free/css/all.min.css';

// Route: /upload-rfid -> UploadRFID component (Excel file upload for RFID data)

const RFIDIntegration = () => {
  const [userInfo, setUserInfo] = useState({});

  useEffect(() => {
    const userInfo = JSON.parse(localStorage.getItem('userInfo')) || {};
    setUserInfo(userInfo);
  }, []);

  // Common style objects
  const buttonHoverStyles = {
    transform: 'translateY(-2px)',
    boxShadow: '0 6px 20px rgba(84, 112, 255, 0.4)'
  };

  const buttonResetStyles = {
    transform: 'translateY(0)',
    boxShadow: '0 4px 14px rgba(84, 112, 255, 0.3)'
  };

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      height: '100vh',
      overflow: 'hidden',
      background: 'linear-gradient(135deg, #f8f9fa 0%, #ececec 100%)'
    }}>
      <Header userInfo={userInfo} />

      <div
        className="hide-scrollbar"
        style={{
          flex: 1,
          overflowY: 'auto',
          background: 'radial-gradient(circle at 60% 40%, #e3f0ff 0%, #fffbe3 100%)',
          background: 'none',
          paddingBottom: '2rem'
        }}
      >
        <div className="container py-5">
          <div className="text-center mb-5">
            <div style={{ 
              width: 90,
              height: 90,
              background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              margin: '0 auto 1.5rem',
              boxShadow: '0 8px 24px #0078d422',
            }}>
              <i className="fas fa-plug fa-3x" style={{ color: 'white' }}></i>
            </div>
            <h1 className="mb-3 fw-bold" style={{ 
              fontSize: '2.4rem', 
              color: '#0078d4', 
              letterSpacing: 0.5,
              background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent'
            }}>
              RFID Integration
            </h1>
            <p className="lead mb-5" style={{ 
              fontSize: '1.2rem', 
              color: '#555', 
              maxWidth: '800px', 
              margin: '0 auto' 
            }}>
              Follow these steps to seamlessly integrate RFID technology with your existing systems.
            </p>
          </div>

          {/* Reusable Tag Section */}
          <div className="card mb-4 border-0 shadow-sm rfid-card rfid-card-reusable" style={{ position: 'relative', borderRadius: '18px', overflow: 'hidden', transition: 'box-shadow 0.2s, transform 0.2s' }}>
            {/* Accent Bar */}
            <div style={{
              position: 'absolute',
              left: 0,
              top: 0,
              bottom: 0,
              width: 8,
              background: 'linear-gradient(180deg, #5470FF 0%, #6C8FFF 100%)',
              borderTopLeftRadius: 18,
              borderBottomLeftRadius: 18,
              boxShadow: '0 0 12px #5470ff55',
              zIndex: 1
            }}></div>
            <div className="card-body p-4" style={{ background: 'linear-gradient(135deg, #e3f0ff 0%, #fafdff 100%)', borderRadius: '18px', border: '1.5px solid #b3d8ff', boxShadow: '0 6px 24px #b3d8ff22', position: 'relative', zIndex: 2 }}>
              <div className="d-flex align-items-center mb-3">
                <div style={{
                  width: 48,
                  height: 48,
                  background: 'linear-gradient(45deg, #5470FF, #6C8FFF)',
                  borderRadius: '50%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginRight: '18px',
                  boxShadow: '0 0 16px #5470ff88, 0 2px 8px #b3d8ff44',
                  border: '2.5px solid #fff',
                }}>
                  <i className="fas fa-redo" style={{ color: '#fff', fontSize: 26, textShadow: '0 0 8px #5470ff88' }}></i>
                </div>
                <h4 className="mb-0 fw-bold" style={{ color: '#2a4d9c', fontFamily: 'Poppins, Inter, sans-serif', fontWeight: 800, fontSize: '1.45rem', letterSpacing: 0.2 }}>Reusable Tag</h4>
              </div>
              <ul style={{ fontSize: '1.08rem', color: '#333', marginLeft: 10, fontFamily: 'Inter, sans-serif' }}>
                <li>To use the reusable tags in your software system, we need one text box like RFID code or RFID no.</li>
                <li>While you do the stock entry, at that time our RFID no has to be scanned (QR code) or the RFID number typed.</li>
                <li>So our RFID number will pair with your item code.</li>
                <li>In existing stocks, customers can edit or put the RFID number in the inventory list.</li>
                <li>For existing stocks, customers can prepare an Excel sheet of matching RFID code and item code.</li>
              </ul>
            </div>
          </div>

          {/* Single Time Use Tag Section */}
          <div className="card mb-4 border-0 shadow-sm rfid-card rfid-card-single" style={{ position: 'relative', borderRadius: '18px', overflow: 'hidden', transition: 'box-shadow 0.2s, transform 0.2s' }}>
            {/* Accent Bar */}
            <div style={{
              position: 'absolute',
              left: 0,
              top: 0,
              bottom: 0,
              width: 8,
              background: 'linear-gradient(180deg, #FF9966 0%, #FF5E62 100%)',
              borderTopLeftRadius: 18,
              borderBottomLeftRadius: 18,
              boxShadow: '0 0 12px #ff996655',
              zIndex: 1
            }}></div>
            <div className="card-body p-4" style={{ background: 'linear-gradient(135deg, #fffbe3 0%, #fff3b3 100%)', borderRadius: '18px', border: '1.5px solid #ffe5b3', boxShadow: '0 6px 24px #ffe5b322', position: 'relative', zIndex: 2 }}>
              <div className="d-flex align-items-center mb-3">
                <div style={{
                  width: 48,
                  height: 48,
                  background: 'linear-gradient(45deg, #FF9966, #FF5E62)',
                  borderRadius: '50%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginRight: '18px',
                  boxShadow: '0 0 16px #ff996688, 0 2px 8px #ffe5b344',
                  border: '2.5px solid #fff',
                }}>
                  <i className="fas fa-tag" style={{ color: '#fff', fontSize: 26, textShadow: '0 0 8px #ff996688' }}></i>
                </div>
                <h4 className="mb-0 fw-bold" style={{ color: '#bfa100', fontFamily: 'Poppins, Inter, sans-serif', fontWeight: 800, fontSize: '1.45rem', letterSpacing: 0.2 }}>Single Time Use Tag</h4>
              </div>
              <ul style={{ fontSize: '1.08rem', color: '#333', marginLeft: 10, fontFamily: 'Inter, sans-serif' }}>
                <li>Single time use tags can be printed or encoded using an RFID printer.</li>
                <li>The RFID printer converts an item code or barcode value to a hexadecimal number.</li>
                <li>The hexadecimal number should be a multiple of four.</li>
                <li>If the hexadecimal code is not a multiple of four, the printer adds "00" at the start or end of the hex code.</li>
                <li>If the exact hexadecimal code matches, the RFID inventory will be scanned.</li>
              </ul>
            </div>
          </div>

          {/* Add hover effect for cards */}
          <style>{`
            .rfid-card:hover {
              box-shadow: 0 12px 32px #b3d8ff44, 0 2px 8px #b3d8ff22;
              transform: translateY(-3px) scale(1.012);
            }
            .rfid-card-single:hover {
              box-shadow: 0 12px 32px #ffe5b344, 0 2px 8px #ffe5b322;
            }
          `}</style>

          <div className="text-center mt-5">
            <div style={{ margin: '2rem auto', maxWidth: '600px' }}>
